import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum UserRole {
  DONOR = 'DONOR',
  VOLUNTEER = 'VOLUNTEER'
}

export enum DonationType {
  FOOD = 'FOOD',
  CLOTHES = 'CLOTHES'
}

export enum DonationStatus {
  AVAILABLE = 'AVAILABLE',
  PICKED_UP = 'PICKED_UP',
  DELIVERED = 'DELIVERED',
  CANCELLED = 'CANCELLED'
}

export interface User {
  id: string;
  name: string;
  email: string;
  role: UserRole;
  avatar: string;
}

export interface Donation {
  id: string;
  donorId: string;
  donorName: string;
  volunteerId?: string;
  title: string;
  description: string;
  type: DonationType;
  status: DonationStatus;
  location: string;
  imageUrl: string;
  createdAt: number;
}

export interface Message {
  id: string;
  donationId: string;
  senderId: string;
  text: string;
  timestamp: number;
}

import React, { useState, useEffect } from 'react';
import { HashRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import Navbar from './components/Navbar';
import LandingPage from './pages/LandingPage';
import AuthPage from './pages/AuthPage';
import Dashboard from './pages/Dashboard';
import CreateDonation from './pages/CreateDonation';
import DonationDetails from './pages/DonationDetails';
import ChatRoom from './pages/ChatRoom';
import { User, UserRole, Donation } from './types';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);

  // Simulate persistent login
  useEffect(() => {
    const savedUser = localStorage.getItem('kindshare_user');
    if (savedUser) {
      setCurrentUser(JSON.parse(savedUser));
    }
    setLoading(false);
  }, []);

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    localStorage.setItem('kindshare_user', JSON.stringify(user));
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem('kindshare_user');
  };

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-emerald-50">
        <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-emerald-600"></div>
      </div>
    );
  }

  return (
    <Router>
      <div className="flex flex-col min-h-screen">
        <Navbar user={currentUser} onLogout={handleLogout} />
        <main className="flex-grow">
          <Routes>
            <Route path="/" element={<LandingPage user={currentUser} />} />
            <Route 
              path="/auth" 
              element={!currentUser ? <AuthPage onLogin={handleLogin} /> : <Navigate to="/dashboard" />} 
            />
            <Route 
              path="/dashboard" 
              element={currentUser ? <Dashboard user={currentUser} /> : <Navigate to="/auth" />} 
            />
            <Route 
              path="/donate" 
              element={currentUser?.role === UserRole.DONOR ? <CreateDonation user={currentUser} /> : <Navigate to="/dashboard" />} 
            />
            <Route 
              path="/donations/:id" 
              element={currentUser ? <DonationDetails user={currentUser} /> : <Navigate to="/auth" />} 
            />
            <Route 
              path="/chat/:id" 
              element={currentUser ? <ChatRoom user={currentUser} /> : <Navigate to="/auth" />} 
            />
          </Routes>
        </main>
      </div>
    </Router>
  );
};

export default App;

