export default AuthPage;

import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { User, UserRole, Donation, DonationStatus, DonationType } from '../types';

interface DashboardProps {
  user: User;
}

const Dashboard: React.FC<DashboardProps> = ({ user }) => {
  const [donations, setDonations] = useState<Donation[]>([]);
  const [filter, setFilter] = useState<DonationStatus | 'ALL'>('ALL');

  useEffect(() => {
    // Mock fetching data
    const mockData: Donation[] = JSON.parse(localStorage.getItem('kindshare_donations') || '[]');

    if (user.role === UserRole.DONOR) {
      setDonations(mockData.filter(d => d.donorId === user.id));
    } else {
      // Volunteers see all available donations or those they claimed
      setDonations(mockData.filter(d => d.status === DonationStatus.AVAILABLE || d.volunteerId === user.id));
    }
  }, [user.id, user.role]);

  const filteredDonations = filter === 'ALL' ? donations : donations.filter(d => d.status === filter);

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-10">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-10 gap-4">
        <div>
          <h1 className="text-3xl font-bold text-gray-900">Welcome, {user.name}!</h1>
          <p className="text-gray-500">
            {user.role === UserRole.DONOR 
              ? 'Manage your donations and see their progress.' 
              : 'Find available donations nearby and start delivering.'}
          </p>
        </div>

        {user.role === UserRole.DONOR && (
          <Link to="/donate" className="bg-emerald-600 text-white px-6 py-3 rounded-xl font-bold hover:bg-emerald-700 transition shadow-lg shadow-emerald-100">
            + New Donation
          </Link>
        )}
      </div>

      <div className="mb-8 flex space-x-2 overflow-x-auto pb-2">
        {['ALL', ...Object.values(DonationStatus)].map((status) => (
          <button
            key={status}
            onClick={() => setFilter(status as any)}
            className={`px-4 py-2 rounded-full text-sm font-medium whitespace-nowrap transition ${
              filter === status 
                ? 'bg-emerald-600 text-white' 
                : 'bg-white text-gray-600 border border-gray-200 hover:border-emerald-300'
            }`}
          >
            {status === 'ALL' ? 'All Items' : status.replace('_', ' ')}
          </button>
        ))}
      </div>

      {filteredDonations.length === 0 ? (
        <div className="bg-white rounded-3xl p-16 text-center shadow-sm border border-gray-100">
          <div className="text-6xl mb-4">🍃</div>
          <h3 className="text-xl font-bold text-gray-900 mb-2">Nothing here yet</h3>
          <p className="text-gray-500 mb-8 max-w-sm mx-auto">
            {user.role === UserRole.DONOR 
              ? "You haven't posted any donations yet. Start by sharing what you have." 
              : "No donations are currently available for pickup. Check back soon!"}
          </p>
          {user.role === UserRole.DONOR && (
            <Link to="/donate" className="text-emerald-600 font-bold hover:underline">Create your first post</Link>
          )}
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {filteredDonations.map((donation) => (
            <Link 
              to={`/donations/${donation.id}`} 
              key={donation.id} 
              className="group bg-white rounded-3xl overflow-hidden shadow-sm hover:shadow-xl transition-all border border-gray-100 flex flex-col"
            >
              <div className="relative h-48">
                <img 
                  src={donation.imageUrl || 'https://picsum.photos/400/300'} 
                  alt={donation.title}
                  className="w-full h-full object-cover group-hover:scale-105 transition duration-500"
                />
                <div className="absolute top-4 left-4">
                  <span className={`px-3 py-1 rounded-full text-xs font-bold uppercase tracking-wider ${
                    donation.type === DonationType.FOOD ? 'bg-orange-100 text-orange-700' : 'bg-blue-100 text-blue-700'
                  }`}>
                    {donation.type}
                  </span>
                </div>
                <div className="absolute top-4 right-4">
                  <span className={`px-3 py-1 rounded-full text-xs font-bold uppercase tracking-wider ${
                    donation.status === DonationStatus.AVAILABLE ? 'bg-emerald-500 text-white' : 'bg-gray-100 text-gray-600'
                  }`}>
                    {donation.status.replace('_', ' ')}
                  </span>
                </div>
              </div>
              <div className="p-6 flex-grow">
                <h3 className="text-xl font-bold text-gray-900 mb-2">{donation.title}</h3>
                <p className="text-gray-500 text-sm mb-4 line-clamp-2">{donation.description}</p>
                <div className="flex items-center text-sm text-gray-400 mb-4">
                  <span className="mr-2">📍</span>
                  <span className="truncate">{donation.location}</span>
                </div>
                <div className="pt-4 border-t border-gray-50 flex justify-between items-center">
                  <div className="flex items-center space-x-2">
                    <span className="text-xs text-gray-400">by</span>
                    <span className="text-xs font-semibold text-gray-700">{donation.donorName}</span>
                  </div>
                  <span className="text-xs text-gray-400">
                    {new Date(donation.createdAt).toLocaleDateString()}
                  </span>
                </div>
              </div>
            </Link>
          ))}
        </div>
      )}
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { User, DonationType, DonationStatus, Donation } from '../types';

interface CreateDonationProps {
  user: User;
}

const CreateDonation: React.FC<CreateDonationProps> = ({ user }) => {
  const navigate = useNavigate();
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [type, setType] = useState<DonationType>(DonationType.FOOD);
  const [location, setLocation] = useState('');
  const [image, setImage] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImage(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleGetLocation = () => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (pos) => {
          // In a real app, use reverse geocoding. Here we simulate.
          setLocation(`${pos.coords.latitude.toFixed(4)}, ${pos.coords.longitude.toFixed(4)} (My Current Location)`);
        },
        (err) => {
          alert("Error getting location. Please enter manually.");
        }
      );
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);

    const newDonation: Donation = {
      id: Math.random().toString(36).substr(2, 9),
      donorId: user.id,
      donorName: user.name,
      title,
      description,
      type,
      status: DonationStatus.AVAILABLE,
      location,
      imageUrl: image || 'https://picsum.photos/800/600',
      createdAt: Date.now()
    };

    // Save to local storage mock database
    const existing = JSON.parse(localStorage.getItem('kindshare_donations') || '[]');
    localStorage.setItem('kindshare_donations', JSON.stringify([newDonation, ...existing]));

    setTimeout(() => {
      setLoading(false);
      navigate('/dashboard');
    }, 1000);
  };

  return (
    <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8 py-12">
      <div className="bg-white rounded-3xl shadow-xl overflow-hidden border border-gray-100">
        <div className="bg-emerald-600 p-8 text-white">
          <h1 className="text-3xl font-bold">Donate Items</h1>
          <p className="opacity-90">Share your food or clothes with the community.</p>
        </div>

        <form onSubmit={handleSubmit} className="p-8 space-y-8">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div className="space-y-6">
              <div>
                <label className="block text-sm font-bold text-gray-700 mb-2">What are you donating?</label>
                <input 
                  type="text" 
                  required
                  placeholder="e.g. Extra sandwiches, Winter coats"
                  className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-emerald-500 outline-none transition"
                  value={title}
                  onChange={(e) => setTitle(e.target.value)}
                />
              </div>

              <div>
                <label className="block text-sm font-bold text-gray-700 mb-2">Description & Details</label>
                <textarea 
                  rows={4}
                  required
                  placeholder="Tell us more about the items, expiry dates (if food), sizes (if clothes), etc."
                  className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-emerald-500 outline-none transition"
                  value={description}
