import React, { useState, useEffect } from 'react';
import { useParams, useNavigate, Link } from 'react-router-dom';
import { User, UserRole, Donation, DonationStatus } from '../types';

interface DonationDetailsProps {
  user: User;
}

const DonationDetails: React.FC<DonationDetailsProps> = ({ user }) => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const [donation, setDonation] = useState<Donation | null>(null);

  useEffect(() => {
    const all = JSON.parse(localStorage.getItem('kindshare_donations') || '[]');
    const found = all.find((d: Donation) => d.id === id);
    if (found) {
      setDonation(found);
    }
  }, [id]);

  const updateStatus = (newStatus: DonationStatus, volunteerId?: string) => {
    if (!donation) return;
    const all = JSON.parse(localStorage.getItem('kindshare_donations') || '[]');
    const updated = all.map((d: Donation) => {
      if (d.id === donation.id) {
        return { ...d, status: newStatus, volunteerId: volunteerId || d.volunteerId };
      }
      return d;
    });
    localStorage.setItem('kindshare_donations', JSON.stringify(updated));
    setDonation({ ...donation, status: newStatus, volunteerId: volunteerId || donation.volunteerId });
  };

  if (!donation) return <div className="p-10 text-center">Loading...</div>;

  const isDonor = donation.donorId === user.id;
  const isVolunteer = user.role === UserRole.VOLUNTEER;
  const isClaimedByMe = donation.volunteerId === user.id;

  return (
    <div className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8 py-10">
      <Link to="/dashboard" className="text-emerald-600 font-medium mb-6 inline-block hover:underline">← Back to Dashboard</Link>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-10">
        <div className="lg:col-span-2 space-y-8">
          <div className="bg-white rounded-3xl overflow-hidden shadow-sm border border-gray-100">
            <img src={donation.imageUrl} alt={donation.title} className="w-full h-96 object-cover" />
            <div className="p-8">
              <div className="flex justify-between items-start mb-4">
                <h1 className="text-4xl font-extrabold text-gray-900">{donation.title}</h1>
                <span className={`px-4 py-1 rounded-full text-xs font-bold uppercase ${
                  donation.status === DonationStatus.AVAILABLE ? 'bg-emerald-500 text-white' : 'bg-orange-500 text-white'
                }`}>
                  {donation.status.replace('_', ' ')}
                </span>
              </div>
              <p className="text-lg text-gray-600 mb-8 whitespace-pre-wrap">{donation.description}</p>

              <div className="grid grid-cols-2 gap-6 p-6 bg-gray-50 rounded-2xl">
                <div>
                  <h4 className="text-xs font-bold text-gray-400 uppercase tracking-widest mb-1">Type</h4>
                  <p className="font-semibold text-gray-900 capitalize">{donation.type.toLowerCase()}</p>
                </div>
                <div>
                  <h4 className="text-xs font-bold text-gray-400 uppercase tracking-widest mb-1">Location</h4>
                  <p className="font-semibold text-gray-900 truncate">{donation.location}</p>
                </div>
                <div>
                  <h4 className="text-xs font-bold text-gray-400 uppercase tracking-widest mb-1">Posted On</h4>
                  <p className="font-semibold text-gray-900">{new Date(donation.createdAt).toLocaleDateString()}</p>
                </div>
                <div>
                  <h4 className="text-xs font-bold text-gray-400 uppercase tracking-widest mb-1">Donor</h4>
                  <p className="font-semibold text-gray-900">{donation.donorName}</p>
                </div>
              </div>
            </div>
          </div>
        </div>

        <div className="space-y-6">
          <div className="bg-white p-8 rounded-3xl shadow-sm border border-gray-100">
            <h2 className="text-xl font-bold text-gray-900 mb-6">Action Center</h2>

            <div className="space-y-4">
              {donation.status === DonationStatus.AVAILABLE && isVolunteer && !isDonor && (
                <button 
                  onClick={() => updateStatus(DonationStatus.PICKED_UP, user.id)}
                  className="w-full py-4 bg-emerald-600 text-white rounded-xl font-bold hover:bg-emerald-700 transition"
                >
                  Claim & Pick Up
                </button>
              )}

              {donation.status === DonationStatus.PICKED_UP && isClaimedByMe && (
                <button 
                  onClick={() => updateStatus(DonationStatus.DELIVERED)}
                  className="w-full py-4 bg-emerald-600 text-white rounded-xl font-bold hover:bg-emerald-700 transition"
                >
                  Mark as Delivered
                </button>
              )}

              {(isClaimedByMe || isDonor) && donation.status !== DonationStatus.AVAILABLE && (
                <Link 
                  to={`/chat/${donation.id}`}
                  className="w-full py-4 flex justify-center items-center bg-white text-emerald-600 border-2 border-emerald-600 rounded-xl font-bold hover:bg-emerald-50 transition"
                >
                  <span className="mr-2">💬</span> Chat with {isDonor ? 'Volunteer' : 'Donor'}
                </Link>
              )}

              {isDonor && donation.status === DonationStatus.AVAILABLE && (
                <button 
                  onClick={() => updateStatus(DonationStatus.CANCELLED)}
                  className="w-full py-4 bg-white text-red-600 border-2 border-red-100 rounded-xl font-bold hover:bg-red-50 transition"
                >
                  Cancel Donation
                </button>
              )}

              {donation.status === DonationStatus.DELIVERED && (
                <div className="p-4 bg-emerald-50 text-emerald-700 rounded-xl text-center font-bold">
                  ✅ Successfully Delivered!
                </div>
              )}
            </div>
          </div>

          <div className="bg-emerald-900 text-white p-8 rounded-3xl shadow-xl">
            <h3 className="font-bold text-lg mb-4">Why it matters?</h3>
            <p className="text-emerald-100 text-sm opacity-80 leading-relaxed">
              Every donation helps reduce waste and provides essential items to vulnerable community members. Thank you for being part of KindShare.
            </p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default DonationDetails;

import React, { useState, useEffect, useRef } from 'react';
import { useParams, Link } from 'react-router-dom';
import { User, Message, Donation } from '../types';

interface ChatRoomProps {
  user: User;
}

const ChatRoom: React.FC<ChatRoomProps> = ({ user }) => {
  const { id } = useParams<{ id: string }>();
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputText, setInputText] = useState('');
  const [donation, setDonation] = useState<Donation | null>(null);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    // Mock fetch donation
    const all = JSON.parse(localStorage.getItem('kindshare_donations') || '[]');
    const found = all.find((d: Donation) => d.id === id);
    if (found) setDonation(found);

    // Mock fetch messages
    const chatKey = `kindshare_chat_${id}`;
    const saved = JSON.parse(localStorage.getItem(chatKey) || '[]');
    setMessages(saved);
  }, [id]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSendMessage = (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputText.trim()) return;

    const newMessage: Message = {
      id: Date.now().toString(),
      donationId: id!,
      senderId: user.id,
      text: inputText,
      timestamp: Date.now()
    };

    const updated = [...messages, newMessage];
    setMessages(updated);
    localStorage.setItem(`kindshare_chat_${id}`, JSON.stringify(updated));
    setInputText('');

    // Auto-reply simulation if needed
  };

  if (!donation) return <div className="p-10 text-center">Loading chat...</div>;

  return (
    <div className="max-w-4xl mx-auto px-4 py-8 h-[calc(100vh-100px)] flex flex-col">
      <div className="bg-white border border-gray-100 rounded-t-3xl p-6 shadow-sm flex items-center justify-between">
        <div className="flex items-center space-x-4">
          <Link to={`/donations/${id}`} className="p-2 hover:bg-gray-100 rounded-full transition">
            ←
          </Link>
          <div>
            <h2 className="font-bold text-gray-900">Coordination Chat</h2>
            <p className="text-xs text-gray-500 uppercase tracking-widest">{donation.title}</p>
          </div>
        </div>
        <div className="flex items-center space-x-2">
           <span className="w-2 h-2 bg-emerald-500 rounded-full"></span>
           <span className="text-xs font-bold text-emerald-600">Active Session</span>
        </div>
      </div>

      <div 
        ref={scrollRef}
        className="flex-grow overflow-y-auto p-6 bg-gray-50 space-y-4"
      >
        {messages.length === 0 ? (
          <div className="text-center py-10 opacity-40">
            <p className="text-sm italic">Start a conversation to coordinate pickup...</p>
          </div>
        ) : (
          messages.map((msg) => (
            <div 
              key={msg.id} 
              className={`flex ${msg.senderId === user.id ? 'justify-end' : 'justify-start'}`}
            >
              <div className={`max-w-[75%] px-4 py-3 rounded-2xl shadow-sm text-sm ${
                msg.senderId === user.id 
                  ? 'bg-emerald-600 text-white rounded-tr-none' 
                  : 'bg-white text-gray-800 rounded-tl-none border border-gray-100'
              }`}>
                {msg.text}
                <div className={`text-[10px] mt-1 opacity-60 text-right`}>
                  {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                </div>
              </div>
            </div>
          ))
        )}
      </div>

      <form 
        onSubmit={handleSendMessage}
        className="bg-white border-t border-gray-100 p-4 rounded-b-3xl shadow-lg flex space-x-2"
      >
        <input 
          type="text" 
          placeholder="Type your message..."
          className="flex-grow px-6 py-3 bg-gray-50 rounded-full outline-none focus:ring-2 focus:ring-emerald-500 text-sm transition"
          value={inputText}
          onChange={(e) => setInputText(e.target.value)}
        />
        <button 
          type="submit"
          className="bg-emerald-600 text-white w-12 h-12 rounded-full flex items-center justify-center hover:bg-emerald-700 transition shadow-md shadow-emerald-100"
        >
          ➔
        </button>
      </form>
    </div>
  );
};

export default ChatRoom;

import React, { useState, useEffect } from 'react';
import { HashRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import Navbar from './components/Navbar';
import LandingPage from './pages/LandingPage';
import AuthPage from './pages/AuthPage';
import Dashboard from './pages/Dashboard';
import CreateDonation from './pages/CreateDonation';
import DonationDetails from './pages/DonationDetails';
import ChatRoom from './pages/ChatRoom';
import { User, UserRole } from './types';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);
  const [isDark, setIsDark] = useState(() => {
    return localStorage.getItem('kindshare_theme') === 'dark';
  });

  useEffect(() => {
    const savedUser = localStorage.getItem('kindshare_user');
    if (savedUser) {
      setCurrentUser(JSON.parse(savedUser));
    }
    setLoading(false);
  }, []);

  useEffect(() => {
    if (isDark) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('kindshare_theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('kindshare_theme', 'light');
    }
  }, [isDark]);

  const toggleTheme = () => setIsDark(!isDark);

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    localStorage.setItem('kindshare_user', JSON.stringify(user));
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem('kindshare_user');
  };

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-emerald-50 dark:bg-gray-950">
        <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-emerald-600"></div>
      </div>
    );
  }

  return (
    <Router>
      <div className="flex flex-col min-h-screen transition-colors duration-300">
        <Navbar user={currentUser} onLogout={handleLogout} isDark={isDark} onToggleTheme={toggleTheme} />
        <main className="flex-grow">
          <Routes>
            <Route path="/" element={<LandingPage user={currentUser} />} />
            <Route 
              path="/auth" 
              element={!currentUser ? <AuthPage onLogin={handleLogin} /> : <Navigate to="/dashboard" />} 
            />
            <Route 
              path="/dashboard" 
              element={currentUser ? <Dashboard user={currentUser} /> : <Navigate to="/auth" />} 
            />
            <Route 
              path="/donate" 
              element={currentUser?.role === UserRole.DONOR ? <CreateDonation user={currentUser} /> : <Navigate to="/dashboard" />} 
            />
            <Route 
              path="/donations/:id" 
              element={currentUser ? <DonationDetails user={currentUser} /> : <Navigate to="/auth" />} 
            />
            <Route 
              path="/chat/:id" 
              element={currentUser ? <ChatRoom user={currentUser} /> : <Navigate to="/auth" />} 
            />
          </Routes>
        </main>
      </div>
    </Router>
  );
};

export default App;

