import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { User, DonationType, DonationStatus, Donation } from '../types';

interface CreateDonationProps {
  user: User;
}

const CreateDonation: React.FC<CreateDonationProps> = ({ user }) => {
  const navigate = useNavigate();
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [type, setType] = useState<DonationType>(DonationType.FOOD);
  const [location, setLocation] = useState('');
  const [image, setImage] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImage(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleGetLocation = () => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (pos) => {
          // Format as lat, lng for the map parser
          setLocation(`${pos.coords.latitude.toFixed(6)}, ${pos.coords.longitude.toFixed(6)}`);
        },
        () => alert("Permission denied. Enter manually.")
      );
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);

    const newDonation: Donation = {
      id: Math.random().toString(36).substr(2, 9),
      donorId: user.id,
      donorName: user.name,
      title,
      description,
      type,
      status: DonationStatus.AVAILABLE,
      location,
      imageUrl: image || 'https://images.unsplash.com/photo-1593113598332-cd288d649433?auto=format&fit=crop&q=80&w=800',
      createdAt: Date.now()
    };

    const existing = JSON.parse(localStorage.getItem('kindshare_donations') || '[]');
    localStorage.setItem('kindshare_donations', JSON.stringify([newDonation, ...existing]));

    setTimeout(() => {
      setLoading(false);
      navigate('/dashboard');
    }, 800);
  };

  return (
    <div className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8 py-12 transition-all">
      <div className="bg-white dark:bg-gray-800 rounded-[3rem] shadow-2xl overflow-hidden border border-gray-100 dark:border-gray-700 flex flex-col md:flex-row">
        {/* Sidebar Info */}
        <div className="md:w-1/3 bg-emerald-600 p-12 text-white flex flex-col justify-between">
            <div>
                <h1 className="text-4xl font-black mb-6 leading-tight">Share Your <br/> Abundance</h1>
                <p className="opacity-90 text-emerald-50 leading-relaxed mb-10">
                    Your small contribution can be the world to someone else. Capture a photo, set your location, and a volunteer will handle the rest.
                </p>
                <div className="space-y-6">
                    <div className="flex items-center space-x-4">
                        <div className="w-10 h-10 bg-emerald-500 rounded-xl flex items-center justify-center text-xl">📸</div>
                        <span className="font-bold">Clear Photos</span>
                    </div>
                    <div className="flex items-center space-x-4">
                        <div className="w-10 h-10 bg-emerald-500 rounded-xl flex items-center justify-center text-xl">📍</div>
                        <span className="font-bold">Precise Location</span>
                    </div>
                </div>
            </div>
            <div className="mt-12 opacity-50 text-xs font-bold uppercase tracking-widest">
                KindShare Community Guidelines Apply
            </div>
        </div>

        {/* Form */}
        <form onSubmit={handleSubmit} className="flex-grow p-12 space-y-8">
          <div className="space-y-6">
            <div>
              <label className="block text-xs font-black text-gray-400 dark:text-gray-500 uppercase tracking-widest mb-3">Item Title</label>
              <input 
                type="text" 
                required
                placeholder="e.g. 5kg Fresh Apples"
                className="w-full px-6 py-4 rounded-2xl bg-gray-50 dark:bg-gray-900 border-none focus:ring-2 focus:ring-emerald-500 outline-none transition dark:text-white placeholder-gray-400"
                value={title}
                onChange={(e) => setTitle(e.target.value)}
              />
            </div>

            <div className="grid grid-cols-2 gap-4">
              <button
                type="button"
                onClick={() => setType(DonationType.FOOD)}
                className={`flex items-center justify-center space-x-3 py-4 rounded-2xl border-2 font-black transition ${
                  type === DonationType.FOOD ? 'border-emerald-600 bg-emerald-50 dark:bg-emerald-950 text-emerald-700 dark:text-emerald-400' : 'border-gray-100 dark:border-gray-700 bg-gray-50 dark:bg-gray-900 text-gray-400'
                }`}
              >
                <span>🍎</span> <span>Food</span>
              </button>
              <button
                type="button"
                onClick={() => setType(DonationType.CLOTHES)}
                className={`flex items-center justify-center space-x-3 py-4 rounded-2xl border-2 font-black transition ${
                  type === DonationType.CLOTHES ? 'border-emerald-600 bg-emerald-50 dark:bg-emerald-950 text-emerald-700 dark:text-emerald-400' : 'border-gray-100 dark:border-gray-700 bg-gray-50 dark:bg-gray-900 text-gray-400'
                }`}
              >
                <span>👕</span> <span>Clothes</span>
              </button>
            </div>

            <div>
              <label className="block text-xs font-black text-gray-400 dark:text-gray-500 uppercase tracking-widest mb-3">Photo</label>
              <div 
                className="group relative border-2 border-dashed border-gray-100 dark:border-gray-700 rounded-3xl p-6 text-center cursor-pointer hover:border-emerald-500 transition h-56 flex flex-col items-center justify-center bg-gray-50 dark:bg-gray-900 overflow-hidden"
                onClick={() => document.getElementById('photo-input')?.click()}
              >
                {image ? (
                  <img src={image} alt="Preview" className="absolute inset-0 w-full h-full object-cover" />
                ) : (
                  <div className="group-hover:scale-110 transition duration-300">
                    <span className="text-5xl mb-4 block">📸</span>
                    <p className="text-sm text-gray-400 font-bold">Tap to upload item photo</p>
                  </div>
                )}
                <input id="photo-input" type="file" accept="image/*" onChange={handleImageChange} className="hidden" />
              </div>
            </div>

            <div>
              <label className="block text-xs font-black text-gray-400 dark:text-gray-500 uppercase tracking-widest mb-3">Location Context</label>
              <div className="flex gap-2">
                <input 
                  type="text" 
                  required
                  placeholder="Street, City or Lat/Lng"
                  className="flex-grow px-6 py-4 rounded-2xl bg-gray-50 dark:bg-gray-900 border-none focus:ring-2 focus:ring-emerald-500 outline-none transition dark:text-white placeholder-gray-400"
                  value={location}
                  onChange={(e) => setLocation(e.target.value)}
                />
                <button 
                  type="button"
                  onClick={handleGetLocation}
                  className="w-14 bg-gray-100 dark:bg-gray-900 rounded-2xl hover:bg-gray-200 dark:hover:bg-gray-700 transition flex items-center justify-center shadow-sm"
                  title="Current Location"
                >
                  📍
                </button>
              </div>
            </div>

            <div>
              <label className="block text-xs font-black text-gray-400 dark:text-gray-500 uppercase tracking-widest mb-3">Description</label>
              <textarea 
                rows={4}
                required
                placeholder="Quantity, condition, best before dates..."
                className="w-full px-6 py-4 rounded-2xl bg-gray-50 dark:bg-gray-900 border-none focus:ring-2 focus:ring-emerald-500 outline-none transition dark:text-white placeholder-gray-400 resize-none"
                value={description}
                onChange={(e) => setDescription(e.target.value)}
              />
            </div>
          </div>

          <button 
            type="submit" 
            disabled={loading}
            className="w-full py-5 bg-emerald-600 text-white rounded-[1.5rem] font-black text-xl hover:bg-emerald-700 transition disabled:opacity-50 shadow-2xl shadow-emerald-200 dark:shadow-none mt-4 hover:scale-[1.02]"
          >
            {loading ? 'Creating Magic...' : 'Publish Donation'}
          </button>
        </form>
      </div>
    </div>
  );
};

export default CreateDonation;

