interface DashboardProps {
  user: User;
}

const Dashboard: React.FC<DashboardProps> = ({ user }) => {
  const [donations, setDonations] = useState<Donation[]>([]);
  const [filter, setFilter] = useState<DonationStatus | 'ALL'>('ALL');
  const [search, setSearch] = useState('');
  const [viewMode, setViewMode] = useState<'grid' | 'map'>(() => {
    return (localStorage.getItem('share_circle_initial_view') as 'grid' | 'map') || 'grid';
  });

  useEffect(() => {
    // Build real-time query
    let q;
    if (user.role === UserRole.DONOR) {
      q = query(
        collection(db, 'donations'), 
        where('donorId', '==', user.id),
        orderBy('createdAt', 'desc')
      );
    } else {
      // Volunteers see everything that's available OR items they've claimed
      q = query(
        collection(db, 'donations'),
        orderBy('createdAt', 'desc')
      );
    }

    const unsubscribe = onSnapshot(q, (snapshot) => {
      const docs = snapshot.docs.map(doc => ({
        id: doc.id,
        ...doc.data()
      })) as Donation[];

      if (user.role === UserRole.VOLUNTEER) {
        // Additional filtering for volunteers if needed on the client side 
        // to simplify the Firestore composite index requirements
        setDonations(docs.filter(d => d.status === DonationStatus.AVAILABLE || d.volunteerId === user.id));
      } else {
        setDonations(docs);
      }
    });

    return () => unsubscribe();
  }, [user.id, user.role]);

  const filteredDonations = donations.filter(d => {
    const statusMatch = filter === 'ALL' || d.status === filter;
    const searchMatch = d.title.toLowerCase().includes(search.toLowerCase()) || d.location.toLowerCase().includes(search.toLowerCase());
    return statusMatch && searchMatch;
  });

  const parseLatLng = (loc: string) => {
    const matches = loc.match(/(-?\d+\.\d+),?\s*(-?\d+\.\d+)/);
    if (matches) return [parseFloat(matches[1]), parseFloat(matches[2])] as [number, number];
    return [51.505, -0.09] as [number, number]; 
  };

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8 transition-all">
