import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { collection, addDoc } from 'firebase/firestore';
import { db } from '../lib/firebase';
import { User, DonationType, DonationStatus } from '../types';
// Import Gemini API
import { GoogleGenAI } from "@google/genai";

interface CreateDonationProps {
  user: User;
}

const CreateDonation: React.FC<CreateDonationProps> = ({ user }) => {
  const navigate = useNavigate();
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [type, setType] = useState<DonationType>(DonationType.FOOD);
  const [location, setLocation] = useState('');
  const [image, setImage] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [aiLoading, setAiLoading] = useState(false);

  // Fix: Gemini AI Assist for generating a kind description
  const handleAiAssist = async () => {
    if (!title) {
      alert("Please enter a title first so I can help you write a description!");
      return;
    }

    setAiLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Write a warm, concise, and helpful description for a donation item.
          Title: ${title}
          Type: ${type}
          Keep it under 100 words and emphasize the positive impact of sharing.`,
      });

      const aiText = response.text;
      if (aiText) {
        setDescription(aiText.trim());
      }
    } catch (error) {
      console.error("Gemini AI Assist error", error);
      alert("AI Assistant is taking a nap. Please try again later!");
    } finally {
      setAiLoading(false);
    }
  };

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImage(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleGetLocation = () => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (pos) => {
          setLocation(`${pos.coords.latitude.toFixed(6)}, ${pos.coords.longitude.toFixed(6)}`);
        },
        () => alert("Permission denied. Enter manually.")
      );
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);

    try {
      await addDoc(collection(db, 'donations'), {
        donorId: user.id,
        donorName: user.name,
        title,
        description,
        type,
        status: DonationStatus.AVAILABLE,
        location,
        imageUrl: image || 'https://images.unsplash.com/photo-1593113598332-cd288d649433?auto=format&fit=crop&q=80&w=800',
        createdAt: Date.now()
      });
      navigate('/dashboard');
    } catch (err) {
      console.error("Error adding donation", err);
      alert("Failed to post donation. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8 py-12 transition-all">
      <div className="bg-white dark:bg-gray-800 rounded-[3rem] shadow-2xl overflow-hidden border border-gray-100 dark:border-gray-700 flex flex-col md:flex-row">
        {/* Sidebar Info */}
        <div className="md:w-1/3 bg-emerald-600 p-12 text-white flex flex-col justify-between">
            <div>
                <h1 className="text-4xl font-black mb-6 leading-tight">Share Your <br/> Abundance</h1>
                <p className="opacity-90 text-emerald-50 leading-relaxed mb-10">
                    Your small contribution can be the world to someone else. Capture a photo, set your location, and a volunteer will handle the rest.
                </p>
                <div className="space-y-6">
                    <div className="flex items-center space-x-4">
                        <div className="w-10 h-10 bg-emerald-500 rounded-xl flex items-center justify-center text-xl">📸</div>
                        <span className="font-bold">Clear Photos</span>
                    </div>
                    <div className="flex items-center space-x-4">
                        <div className="w-10 h-10 bg-emerald-500 rounded-xl flex items-center justify-center text-xl">📍</div>
                        <span className="font-bold">Precise Location</span>
                    </div>
                </div>
            </div>
            <div className="mt-12 opacity-50 text-xs font-bold uppercase tracking-widest text-center">
                Share Circle Community
            </div>
        </div>

        {/* Form */}
        <form onSubmit={handleSubmit} className="flex-grow p-12 space-y-8">
          <div className="space-y-6">
            <div>
              <label className="block text-xs font-black text-gray-400 dark:text-gray-500 uppercase tracking-widest mb-3">Item Title</label>
              <input 
