                  type="text" 
                  required
                  placeholder="e.g. 51.505, -0.09"
                  className="flex-grow px-6 py-4 rounded-2xl bg-gray-50 dark:bg-gray-900 border-none focus:ring-2 focus:ring-emerald-500 outline-none transition dark:text-white placeholder-gray-400"
                  value={location}
                  onChange={(e) => setLocation(e.target.value)}
                />
                <button 
                  type="button"
                  onClick={handleGetLocation}
                  className="w-14 bg-gray-100 dark:bg-gray-900 rounded-2xl hover:bg-gray-200 dark:hover:bg-gray-700 transition flex items-center justify-center shadow-sm"
                  title="Current Location"
                >
                  📍
                </button>
              </div>
            </div>

            <div>
              <div className="flex justify-between items-center mb-3">
                <label className="block text-xs font-black text-gray-400 dark:text-gray-500 uppercase tracking-widest">Description</label>
                <button 
                  type="button"
                  onClick={handleAiAssist}
                  disabled={aiLoading}
                  className="text-[10px] font-black bg-emerald-100 dark:bg-emerald-950 text-emerald-700 dark:text-emerald-400 px-3 py-1 rounded-full hover:scale-105 transition active:scale-95 disabled:opacity-50"
                >
                  {aiLoading ? '✨ Generating...' : '✨ AI Enhance'}
                </button>
              </div>
              <textarea 
                rows={3}
                required
                placeholder="Quantity, condition, best before dates..."
                className="w-full px-6 py-4 rounded-2xl bg-gray-50 dark:bg-gray-900 border-none focus:ring-2 focus:ring-emerald-500 outline-none transition dark:text-white placeholder-gray-400 resize-none"
                value={description}
                onChange={(e) => setDescription(e.target.value)}
              />
            </div>
          </div>

          <button 
            type="submit" 
            disabled={loading}
            className="w-full py-5 bg-emerald-600 text-white rounded-[1.5rem] font-black text-xl hover:bg-emerald-700 transition disabled:opacity-50 shadow-2xl shadow-emerald-200 dark:shadow-none mt-4 hover:scale-[1.02]"
          >
            {loading ? 'Creating Magic...' : 'Publish Donation'}
          </button>
        </form>
      </div>
    </div>
  );
};

